m.RequesteeActENUM,
m.Status,
m.StatusReason,
m.CreatedAt_UTC,
m.CreatedBy,
m.ModifiedAt_UTC,
m.ModifiedBy,
m.RecordDeleted,
  h0.Title AS RequesteeEntityTitle,
  h1.Firstname_fsx,
  h1.Lastname_fsx,
  h1.Username,
  h1.Email_fsx,
  h1.CellPhone_fsx,
  h2e.Title AS RequestTitle
FROM H_RequestStatuses m
  LEFT JOIN H_AAA_EntityProfile h0 ON h0.Id = m.RequesteeEntityId
  LEFT JOIN H_AAA_Synced_UserInfo h1 ON h1.Id = m.RequesteeUserId
  LEFT JOIN H_RequestBases h2 ON h2.Id = m.RequestId
  LEFT JOIN H_AAA_EntityProfile h2e ON h2e.Id = h2.RequesterEntityId
WHERE m.RecordDeleted IS NULL;

