-- ===== definitions.vehicles (H_VehicleProfile) =====
DROP VIEW IF EXISTS Vi_SPC_VehicleCVOs;
CREATE OR REPLACE VIEW Vi_SPC_VehicleCVOs AS
SELECT
  j.Id AS LinkId,
  j.CVOId,
  j.VehicleId,
  j.HasRule,
  j.IssuedDate_UTC,
  j.ExpiryDate_UTC,
  j.RecordKey AS LinkRecordKey,
rel.Id,
rel.EntityId,
rel.RecordKey,
rel.CreatedAt_UTC,
rel.CreatedBy,
rel.ModifiedAt_UTC,
rel.ModifiedBy,
rel.RecordDeleted,
  rh0.Title AS EntityTitle
FROM H_CVOVehicles j
  JOIN H_CVOs rel ON rel.Id = j.CVOId
  LEFT JOIN H_AAA_EntityProfile rh0 ON rh0.Id = rel.EntityId
WHERE j.RecordDeleted IS NULL AND rel.RecordDeleted IS NULL;

DROP VIEW IF EXISTS Vi_SPC_VehiclePermits;
CREATE OR REPLACE VIEW Vi_SPC_VehiclePermits AS
SELECT
j.Id,
j.HUBId,
j.DistributorId,
j.CVOId,
j.VehicleId,
j.DriverId,
j.ActENUM,
j.PermitIssuerId,
j.PermitTypeId,
j.Code,
j.ServiceCategory,
j.IssuedDate_UTC,
j.RecordKey,
j.CreatedAt_UTC,
j.CreatedBy,
j.ModifiedAt_UTC,
j.ModifiedBy,
j.RecordDeleted,
  h2e.Title AS HUBTitle,
  h3e.Title AS CVOTitle,
  h5e.Title AS DistributorTitle,
  h6.Title AS PermitTypeTitle,
  h7e.Title AS PermitIssuerTitle
FROM H_Permits j
  LEFT JOIN H_HUBs h2 ON h2.Id = j.HUBId
  LEFT JOIN H_AAA_EntityProfile h2e ON h2e.Id = h2.EntityId
  LEFT JOIN H_CVOs h3 ON h3.Id = j.CVOId
  LEFT JOIN H_AAA_EntityProfile h3e ON h3e.Id = h3.EntityId
  LEFT JOIN H_Distributors h5 ON h5.Id = j.DistributorId
  LEFT JOIN H_AAA_EntityProfile h5e ON h5e.Id = h5.EntityId
  LEFT JOIN H_PermitTypes h6 ON h6.Id = j.PermitTypeId
  LEFT JOIN H_PermitIssuers h7 ON h7.Id = j.PermitIssuerId
  LEFT JOIN H_AAA_EntityProfile h7e ON h7e.Id = h7.EntityId
WHERE j.RecordDeleted IS NULL;

DROP VIEW IF EXISTS Vi_SPC_VehicleDrivers;
CREATE OR REPLACE VIEW Vi_SPC_VehicleDrivers AS
SELECT
  j.Id AS LinkId,
  j.VehicleId,
  j.DriverId,
  j.HasRule,
  j.IssuedDate_UTC,
  j.ExpiryDate_UTC,
  j.RecordKey AS LinkRecordKey,
rel.Id,
rel.UserId,
rel.PersonCVOId,
rel.RecordKey,
rel.CreatedAt_UTC,
rel.CreatedBy,
rel.ModifiedAt_UTC,
rel.ModifiedBy,
rel.RecordDeleted,
  rh0.Firstname_fsx,
  rh0.Lastname_fsx,
  rh0.Username,
  rh0.Email_fsx,
  rh0.CellPhone_fsx,
  rh1e.Title AS PersonCVOTitle
FROM H_VehicleDrivers j
  JOIN H_Drivers rel ON rel.Id = j.DriverId
  LEFT JOIN H_AAA_Synced_UserInfo rh0 ON rh0.Id = rel.UserId
  LEFT JOIN H_CVOs rh1 ON rh1.Id = rel.PersonCVOId
  LEFT JOIN H_AAA_EntityProfile rh1e ON rh1e.Id = rh1.EntityId
WHERE j.RecordDeleted IS NULL AND rel.RecordDeleted IS NULL;

