-- ===== system.configurations.entity-configs (H_CFG_EntityConfigs) =====
DROP VIEW IF EXISTS Vi_SPC_EntityConfigListSummary;
CREATE OR REPLACE VIEW Vi_SPC_EntityConfigListSummary AS
SELECT
m.Id,
m.PermitIssuerId,
m.HUBId,
m.DistributorId,
m.CVOId,
m.VehicleId,
m.DriverId,
m.ActENUM,
m.ScenarioId,
m.ConfigBaseId,
m.Value,
m.IsOverridable,
m.Signature,
m.CreatedAt_UTC,
m.CreatedBy,
m.ModifiedAt_UTC,
m.ModifiedBy,
m.RecordDeleted,
  h0e.Title AS PermitIssuerTitle,
  h1.Code AS ConfigBaseCode,
  h2e.Title AS DistributorTitle,
  h3e.Title AS ScenarioTitle,
  h5e.Title AS CVOTitle,
  h6e.Title AS HUBTitle
FROM H_CFG_EntityConfigs m
  LEFT JOIN H_PermitIssuers h0 ON h0.Id = m.PermitIssuerId
  LEFT JOIN H_AAA_EntityProfile h0e ON h0e.Id = h0.EntityId
  LEFT JOIN H_CFG_ActionConfigBases h1 ON h1.Id = m.ConfigBaseId
  LEFT JOIN H_Distributors h2 ON h2.Id = m.DistributorId
  LEFT JOIN H_AAA_EntityProfile h2e ON h2e.Id = h2.EntityId
  LEFT JOIN H_AAA_EntityScenarios h3 ON h3.Id = m.ScenarioId
  LEFT JOIN H_AAA_EntityProfile h3e ON h3e.Id = h3.EntityId
  LEFT JOIN H_CVOs h5 ON h5.Id = m.CVOId
  LEFT JOIN H_AAA_EntityProfile h5e ON h5e.Id = h5.EntityId
  LEFT JOIN H_HUBs h6 ON h6.Id = m.HUBId
  LEFT JOIN H_AAA_EntityProfile h6e ON h6e.Id = h6.EntityId
WHERE m.RecordDeleted IS NULL;

